let app_requests = requests
| where timestamp {TimeRange}
| where cloud_RoleName contains 'orders' or cloud_RoleName contains 'chat'
| summarize AppCount=count(), AvgAppDuration=avg(duration) by Source='AppInsights', Service=cloud_RoleName;
let apim_requests = ApiManagementGatewayLogs
| where TimeGenerated {TimeRange}
| where ApiId contains 'orders'
| summarize APIMCount=count(), AvgAPIMDuration=avg(TotalTime) by Source='APIM', Service=ApiId;
union app_requests, apim_requests

let apim_errors = ApiManagementGatewayLogs
| where TimeGenerated {TimeRange}
| where ResponseCode >= 400
| summarize Count=count() by Source='APIM', Status=tostring(ResponseCode), Service=ApiId;
let container_errors = ContainerAppConsoleLogs_CL
| where TimeGenerated {TimeRange}
| where Log_s contains 'ERROR' or Log_s contains 'Traceback'
| summarize Count=count() by Source='ContainerApp', Status='ERROR', Service=ContainerAppName_s;
let cognitive_errors = AzureDiagnostics
| where TimeGenerated {TimeRange}
| where ResourceProvider == 'MICROSOFT.COGNITIVESERVICES'
| where ResultType == 'Failed' or ResultType == 'Error'
| summarize Count=count() by Source='Cognitive', Status=ResultType, Service=OperationName;
union apim_errors, container_errors, cognitive_errors
| order by Count desc

let apim_errors = ApiManagementGatewayLogs
| where TimeGenerated {TimeRange}
| where ResponseCode >= 400
| extend Source='APIM', ErrorTime=TimeGenerated;
let container_errors = ContainerAppConsoleLogs_CL
| where TimeGenerated {TimeRange}
| where Log_s contains 'ERROR' or Log_s contains 'Traceback'
| extend Source='ContainerApp', ErrorTime=TimeGenerated;
union apim_errors, container_errors
| summarize ErrorCount=count() by bin(ErrorTime, 1h), Source
| render barchart
